 function enforceDocumentLock(){if(!state.draft?.validated_at)return;document.querySelectorAll('.erp-paper input,.erp-paper select,.erp-paper textarea,.erp-add-line button,.erp-side-panel input,.erp-side-panel select,.erp-side-panel textarea').forEach(node=>node.disabled=true);document.querySelector('[data-save-document]')?.remove();document.querySelector('.erp-add-line')?.remove();}
 function enhanceDocumentActions(){enhanceDocumentMetadata();enforceDocumentLock();const d=state.draft,actions=document.querySelector('.erp-editor-bar>.actions');if(!d?.id||!actions||d.status!=='draft'||!['deposit_invoice','balance_invoice','credit_note'].includes(d.document_type))return;const node=document.createElement('button');node.className='btn btn-p';node.textContent='Valider';node.onclick=validateInvoice;actions.appendChild(node);}
 function renderLines(d,locked){const options=(state.data.catalog||[]).filter(item=>item.active!==false).map(item=>`<option value="${e(item.reference)} — ${e(item.name)}"></option>`).join('');return`<datalist id="erp-catalog-options">${options}</datalist><div class="erp-lines"><div class="erp-line erp-line-head"><span>Article, service ou désignation</span><span>Qté</span><span>Unité</span><span class="erp-cost">Coût HT</span><span>Vente HT</span><span>Remise</span><span>TVA</span><span>Total</span><span></span></div>${d.lines.map((line,index)=>renderLine(line,index,locked)).join('')}</div>${!locked?`<div class="erp-add-line">${[['item','Nouvelle ligne'],['free_item','Ligne ponctuelle'],['variant','Variante / option'],['discount','Remise'],['text','Texte'],['title','Titre'],['subtitle','Sous-titre'],['section','Section'],['subtotal','Sous-total'],['page_break','Saut de page'],['comment','Commentaire']].map(([type,label])=>button('+ '+label,`PilozApp.addLine('${type}')`,'btn-ghost')).join('')}</div>`:''}`;}
 function sectionSubtotal(index){let start=0;for(let i=index-1;i>=0;i--){if(state.draft.lines[i].line_type==='section'){start=i+1;break;}}return calc().round(state.draft.lines.slice(start,index).filter(line=>['item','free_item'].includes(line.line_type)&&!line.optional).reduce((sum,line)=>sum+calc().line(line).ht,0));}
 function renderLine(line,index,locked){const drag=!locked?`draggable="true" ondragstart="PilozApp.dragLine(${index})" ondragover="event.preventDefault()" ondrop="PilozApp.dropLine(${index})"`:'',special=!['item','free_item'].includes(line.line_type),amounts=calc().line(line),rates=(state.data.vatRates||[]).filter(rate=>rate.active!==false),fallback=[0,2.1,5.5,10,20].map(rate=>({rate,label:`${rate} %`})),vatOptions=(rates.length?rates:fallback).map(rate=>`<option value="${Number(rate.rate)}" ${Number(line.tax_rate)===Number(rate.rate)?'selected':''}>${e(rate.label||rate.rate+' %')}</option>`).join('');if(special)return`<div class="erp-line erp-line-special" ${drag}><input ${locked?'disabled':''} value="${e(line.name||line.description||'')}" placeholder="${e(line.line_type)}" onchange="PilozApp.setLine(${index},'name',this.value)"><span>${e(line.line_type.replaceAll('_',' '))}${line.line_type==='subtotal'?` · ${money(sectionSubtotal(index))}`:''}</span>${!locked?`<button class="ic" onclick="PilozApp.moveLine(${index},-1)">↑</button><button class="ic" onclick="PilozApp.moveLine(${index},1)">↓</button><button class="ic" onclick="PilozApp.removeLine(${index})">×</button>`:''}</div>`;return`<div class="erp-line ${line.optional?'erp-line-optional':''}" ${drag}><div class="erp-line-identity"><input ${locked?'disabled':''} list="erp-catalog-options" value="${e(line.name||'')}" placeholder="Saisir un article, une référence, un service ou une désignation" onchange="PilozApp.matchLineItem(${index},this.value)"><div class="erp-line-reference"><input ${locked?'disabled':''} value="${e(line.reference||'')}" placeholder="Référence" onchange="PilozApp.setLine(${index},'reference',this.value)">${!locked?`<button class="btn btn-ghost" type="button" onclick="PilozApp.quickCreateItemFromLine(${index})">Créer dans le catalogue</button>`:''}</div><textarea ${locked?'disabled':''} placeholder="Description" onchange="PilozApp.setLine(${index},'description',this.value)">${e(line.description||'')}</textarea></div><input ${locked?'disabled':''} aria-label="Quantité" type="number" min="0" step="0.01" value="${line.quantity}" onchange="PilozApp.setLine(${index},'quantity',this.value,true)"><input ${locked?'disabled':''} aria-label="Unité" value="${e(line.unit||'')}" placeholder="Unité" onchange="PilozApp.setLine(${index},'unit',this.value)"><input class="erp-cost" ${locked?'disabled':''} aria-label="Coût d’achat HT" type="number" min="0" step="0.01" value="${line.unit_cost_snapshot}" onchange="PilozApp.setLine(${index},'unit_cost_snapshot',this.value,true)"><input ${locked?'disabled':''} aria-label="Prix de vente HT" type="number" min="0" step="0.01" value="${line.unit_price}" onchange="PilozApp.setLine(${index},'unit_price',this.value,true)"><input ${locked?'disabled':''} aria-label="Remise" type="number" min="0" max="100" step="0.01" value="${line.discount_rate}" onchange="PilozApp.setLine(${index},'discount_rate',this.value,true)"><select ${locked?'disabled':''} aria-label="Taux de TVA configuré" onchange="PilozApp.setLine(${index},'tax_rate',this.value,true)">${vatOptions}</select><div class="erp-line-total"><b>${money(amounts.ht)}</b><small>TVA ${money(amounts.tax)} · TTC ${money(amounts.ttc)}</small><small class="erp-margin">Marge ${money(amounts.margin)} · taux de marge ${amounts.marginRate===null?'—':amounts.marginRate+' %'} · taux de marque ${amounts.markupRate===null?'—':amounts.markupRate+' %'}</small></div><div>${!locked?`<button class="ic" title="${line.optional?'Rendre obligatoire':'Marquer comme option'}" onclick="PilozApp.setLine(${index},'optional',${!line.optional})">◇</button><button class="ic" title="Dupliquer la ligne" onclick="PilozApp.duplicateLine(${index})">⧉</button><button class="ic" title="Supprimer la ligne" onclick="PilozApp.removeLine(${index})">×</button>`:''}</div></div>`;}
 function renderDocumentPanel(d,locked){const targetField=d.document_type==='quote'?'validity_date':'due_date',targetLabel=d.document_type==='quote'?'Date de validité':'Date d’échéance';return`<aside class="erp-side-panel"><h2>Paramètres</h2><label>Date d’émission<input ${locked?'disabled':''} type="date" value="${e(d.issue_date)}" onchange="PilozApp.setDraft('issue_date',this.value)"></label><label>${targetLabel}<input ${locked?'disabled':''} type="date" value="${e(d[targetField]||'')}" onchange="PilozApp.setDraft('${targetField}',this.value)"></label><label>Langue<select ${locked?'disabled':''} onchange="PilozApp.setDraft('language',this.value)"><option value="fr">Français</option><option value="en" ${d.language==='en'?'selected':''}>Anglais</option></select></label><label>Devise<input ${locked?'disabled':''} value="${e(d.currency||'EUR')}" maxlength="3" onchange="PilozApp.setDraft('currency',this.value.toUpperCase())"></label><label>Conditions de paiement<input ${locked?'disabled':''} value="${e(d.payment_terms||'')}" onchange="PilozApp.setDraft('payment_terms',this.value)"></label><label>Mode de paiement<input ${locked?'disabled':''} value="${e(d.payment_method||'')}" onchange="PilozApp.setDraft('payment_method',this.value)"></label><label>Remise globale (%)<input ${locked?'disabled':''} type="number" min="0" max="100" value="${d.discount_rate||0}" onchange="PilozApp.setDraft('discount_rate',this.value,true)"></label><label>Notes internes<textarea ${locked?'disabled':''} onchange="PilozApp.setDraft('internal_notes',this.value)">${e(d.internal_notes||'')}</textarea></label></aside>`;}
