 async function finalizeCurrentDocument(){
  if(!state.draft?.id||state.busy)return null;
  const id=state.draft.id,isQuote=state.draft.document_type==='quote';
  if(!await ensureCompanyReadyForDocuments())return null;
  state.busy=true;
  const action=document.querySelector('[data-finalize-document]');
  if(action){action.disabled=true;action.textContent=isQuote?'Enregistrement…':'Finalisation…';}
  try{
   let result=null;
   try{result=await api().rpc('finalize_document',{target_document_id:id});}
   catch(error){
    if(!missingRpc(error))throw error;
    result=await api().rpc('validate_invoice',{target_document_id:id});
   }
   const pdfQueued=!!result?.snapshot_id;
   let pdfReady=false;
   if(pdfQueued){
    try{const pdf=await api().invoke('generate-document-pdf',{documentId:id});pdfReady=!!pdf?.ready;}
    catch(error){console.warn('[PILOZ PDF] PDF final en attente',{code:error?.code||'',status:error?.status||0,message:error?.message||String(error)});}
   }
   await refresh();
   hydrateDraftFrom(id);
   const label=isQuote?'Devis enregistré.':'Facture finalisée et verrouillée.';
   notice(pdfReady?`${label} PDF définitif généré.`:pdfQueued?`${label} Le PDF définitif reste en attente de génération.`:label,'success');
   return result;
  }catch(error){
   console.error('[PILOZ Documents] Échec d’enregistrement',{code:error?.code||'',status:error?.status||0,message:error?.message||String(error)});
    const reason=String(error?.message||'').trim(),fallback=isQuote?'L’enregistrement a échoué. Vos informations ont été conservées.':'La finalisation a échoué. Le brouillon reste modifiable et aucune numérotation officielle n’a été perdue.';
    notice(reason?`${fallback} Motif : ${reason}`:fallback,'error');
   return null;
  }finally{
   state.busy=false;
    if(action){action.disabled=false;action.textContent=isQuote?'Enregistrer':'Finaliser la facture';}
  }
 }
