 async function setTemplateStatus(id,value){try{await api().update('document_templates',id,{status:value,is_default:value==='active'?(state.data.templates||[]).find(x=>x.id===id)?.is_default:false});await refresh();notice('Statut du modèle mis à jour.','success');}catch(error){notice(error.message,'error');}}
 async function setTemplateDefault(id){const template=(state.data.templates||[]).find(x=>x.id===id);if(!template)return;try{const siblings=(state.data.templates||[]).filter(x=>x.document_type===template.document_type&&x.language===template.language&&x.id!==id&&x.is_default);for(const sibling of siblings)await api().update('document_templates',sibling.id,{is_default:false});await api().update('document_templates',id,{status:'active',is_default:true});await saveDefaultTemplateSetting(id,template.document_type);await refresh();renderTemplates();notice('Modèle par défaut mis à jour.','success');}catch(error){notice(error.message,'error');}}
 async function deleteTemplate(id){const template=(state.data.templates||[]).find(x=>x.id===id);if(!template)return;if(template.is_default){notice('La suppression d’un modèle par défaut n’est pas autorisée.','error');return;}if(!confirm(`Supprimer le modèle « ${template.name} » ? Cette action est irréversible.`))return;try{await api().remove('document_templates',id);await refresh();renderTemplates();notice('Modèle supprimé.','success');}catch(error){notice(error.message||'Suppression impossible : ce modèle est peut-être utilisé par des documents ou des réglages par défaut.','error');}}
 function setTemplatePaymentMethod(key,enabled){const t=state.templateDraft,current=new Set(Array.isArray(t.payment_methods)&&t.payment_methods.length?t.payment_methods:['bank_transfer']);if(enabled)current.add(key);else current.delete(key);t.payment_methods=[...current];renderTemplateEditor();}
 async function exportTemplate(id){await editTemplate(id);const t=state.templateDraft,blob=new Blob([JSON.stringify({format:'piloz-template-v1',name:t.name,document_type:t.document_type,language:t.language,visual_schema:t.visual_schema,html:t.html,css:t.css},null,2)],{type:'application/json'}),url=URL.createObjectURL(blob),link=document.createElement('a');link.href=url;link.download=(t.name||'modele').replace(/[^a-z0-9_-]+/gi,'-')+'.json';link.click();URL.revokeObjectURL(url);go('templates');}
 async function importTemplate(file){if(!file)return;try{const data=JSON.parse(await file.text());if(data.format!=='piloz-template-v1')throw new Error('Format de modèle non reconnu.');state.templateDraft={...defaultTemplate(),name:data.name||'Modèle importé',document_type:data.document_type||'quote',language:data.language||'fr',visual_schema:data.visual_schema||{blocks:[]},html:data.html||'',css:data.css||''};go('template-editor');notice('Modèle importé. Vérifiez-le puis enregistrez une version.');}catch(error){notice(error.message,'error');}}
 async function restoreTemplateVersion(id){const version=(state.templateDraft.versions||[]).find(x=>x.id===id);if(!version)return;Object.assign(state.templateDraft,{visual_schema:structuredClone(version.visual_schema),html:version.html,css:version.css,mode:'preview'});renderTemplateEditor();notice('Version chargée. Enregistrez pour créer une nouvelle version restaurée.');}

 function renderReports(){const docs=state.data.documents||[],sales=docs.filter(x=>['invoice','quote'].includes(x.document_type)),byClient=new Map(),byItem=new Map();sales.forEach(doc=>{const name=doc.client?.legal_name||'Sans client',row=byClient.get(name)||{sales:0,cost:0};row.sales+=Number(doc.total_excl_tax);row.cost+=Number(doc.total_cost);byClient.set(name,row);});(state.data.lines||[]).forEach(line=>{if(!line.item_id)return;const item=(state.data.catalog||[]).find(x=>x.id===line.item_id),name=item?.name||line.name,row=byItem.get(name)||{sales:0,cost:0};row.sales+=Number(line.total_excl_tax);row.cost+=Number(line.quantity)*Number(line.unit_cost_snapshot);byItem.set(name,row);});document.getElementById('main').innerHTML=top('Rapports de marge et de stock')+`<div class="erp-grid-2"><section class="phase1-card"><h2>Marge par client</h2>${reportTable(byClient)}</section><section class="phase1-card"><h2>Marge par article</h2>${reportTable(byItem)}</section></div><section class="phase1-card"><h2>Historique des coûts</h2><div class="phase1-table-wrap"><table class="phase1-table"><tr><th>Date</th><th>Article</th><th>Ancien coût</th><th>Nouveau coût</th><th>Quantité reçue</th></tr>${(state.data.costHistory||[]).map(x=>`<tr><td>${date(x.created_at)}</td><td>${e((state.data.catalog||[]).find(i=>i.id===x.item_id)?.name||'—')}</td><td>${money(x.previous_cost)}</td><td>${money(x.new_cost)}</td><td>${x.quantity_received||'—'}</td></tr>`).join('')}</table></div></section>`;}
 function enhanceMarginReports(){const main=document.getElementById('main'),documents=new Map((state.data.documents||[]).map(doc=>[doc.id,doc])),byCategory=new Map(),bySalesperson=new Map(),byPeriod=new Map();for(const line of state.data.lines||[]){const doc=documents.get(line.document_id);if(!doc||!['quote','invoice'].includes(doc.document_type))continue;const item=(state.data.catalog||[]).find(x=>x.id===line.item_id),category=item?.category||'Sans catégorie',sales=Number(line.total_excl_tax)||0,cost=Number(line.quantity)*Number(line.unit_cost_snapshot),categoryRow=byCategory.get(category)||{sales:0,cost:0};categoryRow.sales+=sales;categoryRow.cost+=cost;byCategory.set(category,categoryRow);}for(const doc of state.data.documents||[]){if(!['quote','invoice'].includes(doc.document_type))continue;const salesperson=doc.assigned_user_id||'Non attribué',period=String(doc.issue_date||'').slice(0,7)||'Sans date';for(const [map,key] of [[bySalesperson,salesperson],[byPeriod,period]]){const row=map.get(key)||{sales:0,cost:0};row.sales+=Number(doc.total_excl_tax);row.cost+=Number(doc.total_cost);map.set(key,row);}}const section=document.createElement('div');section.className='erp-grid-2';section.innerHTML=`<section class="phase1-card"><h2>Marge par catégorie</h2>${reportTable(byCategory)}</section><section class="phase1-card"><h2>Marge par commercial</h2>${reportTable(bySalesperson)}</section><section class="phase1-card"><h2>Marge par période</h2>${reportTable(byPeriod)}</section>`;main.appendChild(section);}
 const renderReportsBase=renderReports;renderReports=function(){if(!allowed('view_margins')){document.getElementById('main').innerHTML=top('Rapports')+empty('Accès restreint','Votre rôle ne permet pas de consulter les marges.');return;}renderReportsBase();enhanceMarginReports();};
 function reportTable(map){return`<table class="phase1-table"><tr><th>Élément</th><th>Ventes HT</th><th>Coût historique</th><th>Marge</th></tr>${[...map].sort((a,b)=>b[1].sales-a[1].sales).map(([name,row])=>`<tr><td>${e(name)}</td><td>${money(row.sales)}</td><td>${money(row.cost)}</td><td><b>${money(row.sales-row.cost)}</b></td></tr>`).join('')}</table>`;}

 function renderSettings(){const s=state.data.settings?.[0]||{};document.getElementById('main').innerHTML=top('Paramètres de l’entreprise',button('Enregistrer','PilozApp.saveSettings()','btn-p'))+`<div class="erp-settings-layout"><aside class="phase1-settings-nav"><h2>Mon entreprise</h2><a href="#settings-company">Identité</a><a href="#settings-address">Adresse</a><a href="#settings-contact">Coordonnées</a><a href="#settings-logo">Logo</a><a href="#settings-tax">Fiscalité</a><h2>Documents</h2><a href="#settings-documents">Numérotation</a><a href="#settings-footers">Pieds de page</a><a href="#templates">Modèles</a><h2>Catalogue & stock</h2><a href="#sales/catalog">Articles</a><a href="#stock/warehouses">Entrepôts</a><a href="#purchases/suppliers">Fournisseurs</a></aside><form id="company-settings-form" class="erp-settings-content" onsubmit="return false"><section id="settings-company" class="phase1-card"><h2>Identité et informations légales</h2><div class="phase1-grid">${field('Raison sociale *','legal_name',s.legal_name,'text','required')}${field('Nom commercial','trade_name',s.trade_name)}${field('Forme juridique *','legal_form',s.legal_form,'text','required')}${field('SIREN','siren',s.siren)}${field('SIRET *','siret',s.siret,'text','required')}${field('Code APE / NAF','ape_code',s.ape_code)}${field('Activité principale','activity',s.activity)}${field('Date de création','creation_date',s.creation_date,'date')}${field('Site internet','website',s.website,'url')}<p class="phase1-note full">Source : ${e(s.data_source||'Saisie manuelle')} · Récupération : ${date(s.data_retrieved_at)}</p></div></section><section id="settings-address" class="phase1-card"><h2>Adresse</h2><div class="phase1-grid"><div class="phase1-field full"><span>Recherche prédictive</span><input id="settings-address-search" placeholder="Commencez à saisir une adresse" oninput="PilozApp.searchAddress(this.value)"><div id="settings-address-results" class="phase1-search-results"></div></div>${field('Adresse','address_line1',s.address_line1)}${field('Complément','address_line2',s.address_line2)}${field('Code postal','postal_code',s.postal_code)}${field('Ville','city',s.city)}${field('Code pays','country_code',s.country_code||'FR')}</div></section><section id="settings-contact" class="phase1-card"><h2>Coordonnées</h2><div class="phase1-grid">${field('E-mail professionnel','email',s.email,'email')}${field('Téléphone professionnel','phone',s.phone||s.phone_e164,'tel')}<div><span>${s.email_confirmed_at?'E-mail confirmé le '+date(s.email_confirmed_at):'E-mail non confirmé'}</span>${!s.email_confirmed_at?button('Envoyer la confirmation','PilozApp.requestEmailConfirmation()'):''}</div><div><span>${s.phone_verified_at?'Téléphone vérifié':'Téléphone non vérifié — aucun SMS simulé'}</span></div></div></section><section id="settings-logo" class="phase1-card"><h2>Identité visuelle</h2><div class="erp-logo-upload"><label class="erp-dropzone">Logo clair<input type="file" accept="image/png,image/jpeg,image/svg+xml" onchange="PilozApp.uploadLogo(this.files[0],'light')"></label><label class="erp-dropzone">Logo sombre<input type="file" accept="image/png,image/jpeg,image/svg+xml" onchange="PilozApp.uploadLogo(this.files[0],'dark')"></label></div><p>PNG, JPEG ou SVG sécurisé, 5 Mo maximum. Les logos sont stockés dans un bucket privé isolé par entreprise.</p></section><section id="settings-tax" class="phase1-card"><h2>Fiscalité</h2><div class="phase1-grid"><label class="phase1-field"><span>Assujettie à la TVA</span><select name="subject_to_vat"><option value="false" ${s.subject_to_vat===false?'selected':''}>Non</option><option value="true" ${s.subject_to_vat?'selected':''}>Oui</option></select></label>${field('N° TVA intracommunautaire','vat_number',s.vat_number)}${field('Régime de TVA','vat_regime',s.vat_regime)}${field('Taux de TVA par défaut','default_vat_rate',s.default_vat_rate??20,'number','step="0.01"')}${field('Devise','currency',s.currency||'EUR')}${field('Langue','language',s.language||'fr')}</div></section><section id="settings-documents" class="phase1-card"><h2>Documents et numérotation</h2><p>Les numéros définitifs sont attribués par transaction SQL avec verrou de ligne. Configurez les préfixes dans la table des séquences.</p><div class="erp-doc-examples"><code>DEV-${new Date().getFullYear()}-0001</code><code>FAC-${new Date().getFullYear()}-0001</code><code>AV-${new Date().getFullYear()}-0001</code></div></section><section id="settings-footers" class="phase1-card"><h2>Pieds de page</h2><p>Créez plusieurs pieds de page réutilisables entre vos modèles de devis et de factures.</p>${renderFooterList()}${button('Créer un pied de page','PilozApp.openFooterForm()','btn-p')}</section></form></div>`;}
 const footerTokens=[['@nomEntreprise','Raison sociale'],['@nomCommercial','Nom commercial'],['@siren','SIREN'],['@siret','SIRET'],['@tva','N° de TVA'],['@ape','Code APE / NAF'],['@rcs','RCS'],['@capitalSocial','Capital social'],['@adresse','Adresse complète'],['@email','E-mail'],['@telephone','Téléphone'],['@site','Site internet']];
 function resolveFooterTokens(value,company=state.data.settings?.[0]||{}){const values={'@nomEntreprise':company.legal_name,'@nomCommercial':company.trade_name||company.legal_name,'@siren':company.siren,'@siret':company.siret,'@tva':company.vat_number,'@ape':company.ape_code,'@rcs':company.rcs_number,'@capitalSocial':company.social_capital,'@adresse':[company.address_line1||company.address_line_1,company.address_line2||company.address_line_2,[company.postal_code,company.city].filter(Boolean).join(' '),company.country||company.country_code].filter(Boolean).join(', '),'@email':company.email,'@telephone':company.phone||company.phone_e164,'@site':company.website};return footerTokens.reduce((output,[token])=>output.split(token).join(String(values[token]||'')),String(value||''));}
 function footerDisplayName(footer){return footer?.name==='Mentions légales par défaut'?'Pied de page légal par défaut':(footer?.name||'Pied de page légal par défaut');}
 function renderFooterList(){const rows=state.data.documentFooters||[];if(!rows.length)return'<p class="phase1-note">Aucun pied de page créé.</p>';return`<div class="card phase1-table-wrap" style="padding:0"><table class="phase1-table"><tr><th>Nom</th><th>Par défaut</th><th>Statut</th><th>Actions</th></tr>${rows.map(f=>`<tr><td><b>${e(footerDisplayName(f))}</b></td><td><div class="erp-footer-defaults"><button type="button" class="${f.is_default_quote?'on':''}" onclick="PilozApp.setFooterDefault('${f.id}','quote')" title="Définir pour les devis">Devis${f.is_default_quote?' ✓':''}</button><button type="button" class="${f.is_default_invoice?'on':''}" onclick="PilozApp.setFooterDefault('${f.id}','invoice')" title="Définir pour les factures">Factures${f.is_default_invoice?' ✓':''}</button></div></td><td><button type="button" class="erp-footer-status ${f.is_active===false?'inactive':'active'}" onclick="PilozApp.toggleFooterActive('${f.id}',${f.is_active===false})" title="${f.is_active===false?'Activer':'Désactiver'} ce pied de page">${f.is_active===false?'Inactif':'Actif'}</button></td><td><div class="erp-row-actions"><button type="button" class="ic" title="Modifier" onclick="PilozApp.openFooterForm('${f.id}')">✎</button><button type="button" class="ic" title="Dupliquer" onclick="PilozApp.duplicateFooter('${f.id}')">⧉</button><button type="button" class="ic" title="Supprimer" onclick="PilozApp.deleteFooter('${f.id}')">🗑</button></div></td></tr>`).join('')}</table></div>`;}
 function openFooterForm(id=null){const f=(state.data.documentFooters||[]).find(x=>x.id===id)||{},quoteChecked=id?!!f.is_default_quote:true,invoiceChecked=id?!!f.is_default_invoice:true,tokens=footerTokens.map(([token,label])=>`<button type="button" title="${e(label)}" onclick="PilozApp.insertFooterToken('${token}')">${e(token)}</button>`).join('');modal(id?'Modifier le pied de page':'Nouveau pied de page',`<form id="footer-form" class="phase1-grid" onsubmit="return false">${field('Nom *','name',footerDisplayName(f),'text','required')}<div class="erp-footer-targets full"><b>Utiliser ce pied de page sur</b><div><label class="phase1-check"><input name="is_default_quote" type="checkbox" ${quoteChecked?'checked':''}><span>Devis</span></label><label class="phase1-check"><input name="is_default_invoice" type="checkbox" ${invoiceChecked?'checked':''}><span>Factures</span></label></div></div><label class="phase1-field full"><span>Texte du pied de page</span><textarea name="body" rows="4" placeholder="Ex. @nomEntreprise · SIREN @siren · @email">${e(f.body||'')}</textarea></label><div class="erp-footer-token-picker full"><b>Insérer une donnée de l’entreprise</b><small>Cliquez sur une balise pour l’ajouter au texte.</small><div>${tokens}</div></div><label class="phase1-check"><input name="show_legal_mentions" type="checkbox" ${f.show_legal_mentions!==false?'checked':''}><span>Afficher les mentions légales</span></label><label class="phase1-check"><input name="show_bank_details" type="checkbox" ${f.show_bank_details!==false?'checked':''}><span>Afficher les coordonnées bancaires</span></label><label class="phase1-check"><input name="show_payment_terms" type="checkbox" ${f.show_payment_terms!==false?'checked':''}><span>Afficher les conditions de paiement</span></label><label class="phase1-check"><input name="show_late_penalties" type="checkbox" ${f.show_late_penalties!==false?'checked':''}><span>Afficher les pénalités de retard</span></label><label class="phase1-check"><input name="show_page_number" type="checkbox" ${f.show_page_number!==false?'checked':''}><span>Afficher le numéro de page</span></label></form>`,button('Annuler','PilozApp.closeModal()')+button('Enregistrer',`PilozApp.saveFooter('${id||''}')`,'btn-p'));}
 function insertFooterToken(token){const area=document.querySelector('#footer-form textarea[name="body"]');if(!area)return;const start=area.selectionStart??area.value.length,end=area.selectionEnd??start,before=area.value.slice(0,start),after=area.value.slice(end),prefix=before&&!/\s$/.test(before)?' ':'',suffix=after&&!/^\s/.test(after)?' ':'';area.value=before+prefix+token+suffix+after;const cursor=start+prefix.length+token.length+suffix.length;area.focus();area.setSelectionRange(cursor,cursor);}
 async function saveFooter(id){const form=document.getElementById('footer-form'),fd=new FormData(form),data=Object.fromEntries(fd),current=(state.data.documentFooters||[]).find(row=>row.id===id),defaultQuote=fd.has('is_default_quote'),defaultInvoice=fd.has('is_default_invoice');if(!String(data.name||'').trim()){notice('Le nom est obligatoire.','error');return;}const payload={company_id:state.companyId,name:data.name.trim(),body:data.body||null,show_legal_mentions:fd.has('show_legal_mentions'),show_bank_details:fd.has('show_bank_details'),show_payment_terms:fd.has('show_payment_terms'),show_late_penalties:fd.has('show_late_penalties'),show_page_number:fd.has('show_page_number'),is_default_quote:defaultQuote,is_default_invoice:defaultInvoice,is_default:!!(current?.is_default&&defaultQuote&&defaultInvoice)};try{if(id)await api().update('document_footers',id,payload);else await api().insert('document_footers',payload);closeModal();await refresh();notice('Pied de page enregistré.','success');}catch(error){notice(error.message,'error');}}
 async function duplicateFooter(id){const source=(state.data.documentFooters||[]).find(row=>row.id===id);if(!source)return;const payload={company_id:state.companyId,name:`${source.name||'Pied de page'} (copie)`,body:source.body||null,show_legal_mentions:source.show_legal_mentions!==false,show_bank_details:source.show_bank_details!==false,show_payment_terms:source.show_payment_terms!==false,show_late_penalties:source.show_late_penalties!==false,show_page_number:source.show_page_number!==false,is_default_quote:false,is_default_invoice:false,is_default:false,is_active:true};try{await api().insert('document_footers',payload);await refresh();notice('Pied de page dupliqué.','success');}catch(error){notice(error.message||'Duplication impossible.','error');}}
 async function setFooterDefault(id,type='quote'){try{await api().update('document_footers',id,{[type==='invoice'?'is_default_invoice':'is_default_quote']:true});await refresh();notice(`Pied de page par défaut des ${type==='invoice'?'factures':'devis'} mis à jour.`,'success');}catch(error){notice(error.message,'error');}}
 async function toggleFooterActive(id,activate){try{await api().update('document_footers',id,{is_active:activate});await refresh();notice(activate?'Pied de page activé.':'Pied de page désactivé.','success');}catch(error){notice(error.message,'error');}}
 async function deleteFooter(id){if(!confirm('Supprimer ce pied de page ?'))return;try{await api().remove('document_footers',id);await refresh();notice('Pied de page supprimé.','success');}catch(error){notice(error.message||'Suppression impossible : ce pied de page est peut-être utilisé par un modèle.','error');}}
 async function saveSettings(){const form=document.getElementById('company-settings-form'),data=Object.fromEntries(new FormData(form));data.subject_to_vat=data.subject_to_vat==='true';data.default_vat_rate=Number(data.default_vat_rate)||0;data.email=String(data.email||'').trim().toLowerCase();const normalizedPhone=calc().e164(data.phone,'FR');if(data.phone&&!normalizedPhone){notice('Numéro de téléphone invalide.','error');return;}data.phone_e164=normalizedPhone;delete data.phone;if(data.siret&&!calc().validSiren(data.siret)){notice('SIRET invalide.','error');return;}try{await api().upsertCompanySettings(state.companyId,data);await refresh();notice('Paramètres enregistrés.','success');}catch(error){notice(error.message,'error');}}
 let addressTimer=null,addressController=null;
 function searchAddress(value){clearTimeout(addressTimer);addressController?.abort();const q=value.trim();if(q.length<3){renderAddressResults([]);return;}addressTimer=setTimeout(async()=>{addressController=new AbortController();try{const data=await api().invoke('address-search',{query:q},addressController.signal);renderAddressResults(data.results||[]);}catch(error){if(error.name!=='AbortError')notice(error.message,'error');}},300);}
 function renderAddressResults(results){const node=document.getElementById('settings-address-results');if(!node)return;global.__pilozAddressResults=results;node.innerHTML=results.map((x,index)=>`<button type="button" onclick="PilozApp.selectAddress(${index})"><b>${e(x.label)}</b><small>${e([x.postalCode,x.city].filter(Boolean).join(' '))}</small></button>`).join('');}
 function selectAddress(index){const x=global.__pilozAddressResults?.[index],form=document.getElementById('company-settings-form');if(!x||!form)return;['address_line1','address_line2','postal_code','city','country_code'].forEach(name=>{const mapping={address_line1:'addressLine1',address_line2:'addressLine2',postal_code:'postalCode',city:'city',country_code:'countryCode'};form.elements[name].value=x[mapping[name]]||'';});renderAddressResults([]);}
 async function requestEmailConfirmation(){const email=document.querySelector('#company-settings-form [name="email"]')?.value;try{await api().invoke('request-company-email-confirmation',{companyId:state.companyId,email});notice('E-mail de confirmation envoyé.','success');}catch(error){notice(error.message,'error');}}
 function enhancePhoneVerification(){const section=document.getElementById('settings-contact');if(section&&!section.querySelector('[data-phone-verify]')&&!state.data.settings?.[0]?.phone_verified_at){const buttonNode=document.createElement('button');buttonNode.type='button';buttonNode.className='btn btn-o';buttonNode.dataset.phoneVerify='';buttonNode.textContent='Vérifier par SMS';buttonNode.onclick=requestPhoneVerification;section.appendChild(buttonNode);}}
 async function updateMember(userId,key,value){const member=(state.data.members||[]).find(x=>x.user_id===userId);if(!member)return;const data=key==='role'?{role:value}:{permissions:{...(member.permissions||{}),[key]:value}};try{await api().request(`/rest/v1/company_members?company_id=eq.${state.companyId}&user_id=eq.${userId}`,{method:'PATCH',body:JSON.stringify(data)});await refresh();notice('Permissions enregistrées.','success');}catch(error){notice(error.message,'error');}}
