  if(raw.siret&&!calc().validSiren(raw.siret)){notice('SIREN ou SIRET invalide.','error');return;}
  const iban=String(read('ext-iban')||'').replace(/\s+/g,'').toUpperCase();
  if(!validIban(iban)){notice('IBAN invalide.','error');return;}
  const baseKeys=['legal_name','trade_name','legal_form','siren','siret','ape_code','activity','creation_date','website','address_line1','address_line2','postal_code','city','country_code','email','vat_number','vat_regime','currency','language'];
