  const extended=Object.fromEntries(extendedKeys.map(key=>[key,raw[key]||null]));extended.social_capital=raw.social_capital===''?null:Number(raw.social_capital);
  const docsRow=state.data.docSettings?.[0]||{},docPayload={company_id:state.companyId,bank_account_holder:read('ext-bank-holder'),bank_name:read('ext-bank-name'),iban:iban||null,bic:String(read('ext-bic')||'').replace(/\s+/g,'').toUpperCase()||null};
  if(Object.prototype.hasOwnProperty.call(docsRow,'mandate_reference'))docPayload.mandate_reference=read('ext-mandate-reference');
  const addressPayloads=['registered','billing','shipping'].map(kind=>{const registered=kind==='registered',value=key=>registered?(form.elements[{address_line_1:'address_line1',address_line_2:'address_line2',postal_code:'postal_code',city:'city',country_code:'country_code'}[key]]?.value||''):(document.getElementById(`addr-${kind}-${key}`)?.value||'');return{kind,address_line_1:value('address_line_1')||null,address_line_2:value('address_line_2')||null,postal_code:value('postal_code')||null,city:value('city')||null,country_code:value('country_code')||'FR',is_primary:registered||!!document.getElementById(`addr-${kind}-primary`)?.checked};});
  state.busy=true;
  try{
   await api().upsertCompanySettings(state.companyId,base);
   await api().request('/rest/v1/company_document_settings?on_conflict=company_id',{method:'POST',headers:{Prefer:'resolution=merge-duplicates,return=minimal'},body:JSON.stringify(docPayload)});
   const fallback=legacyCompanyDetails(true);Object.assign(fallback,extended,{mandate_reference:read('ext-mandate-reference')});global.sauver?.();
   const failures=[],optional=async(label,action)=>{try{await action();}catch(error){failures.push(label);console.error('[PILOZ Paramètres] Complément non enregistré',{section:label,status:error?.status||0,code:error?.code||'',message:error?.message||String(error)});}};
   if(Object.prototype.hasOwnProperty.call(settingsRow,'company_type'))await optional('informations légales',()=>api().upsertCompanySettings(state.companyId,extended));
   for(const payload of addressPayloads)await optional(`adresse ${payload.kind}`,async()=>{const existing=(state.data.addresses||[]).find(x=>x.kind===payload.kind);if(existing)await api().update('company_addresses',existing.id,payload);else if(payload.address_line_1||payload.city)await api().insert('company_addresses',{company_id:state.companyId,...payload});});
   await refresh();notice(failures.length?`Les paramètres principaux sont enregistrés. À vérifier : ${failures.join(', ')}.`:'Paramètres de l’entreprise enregistrés.',failures.length?'info':'success');
  }catch(error){console.error('[PILOZ Paramètres] Échec de sauvegarde',{status:error?.status||0,code:error?.code||'',message:error?.message||String(error)});notice('Les paramètres n’ont pas pu être enregistrés. Vérifiez les champs et réessayez.','error');}
  finally{state.busy=false;}
